import "./notificationList.css";
import { NavLink } from 'react-router-dom';
import { useDispatch, useSelector } from 'react-redux';
import notificationAdapter, { getAllNotifications, notificationRead } from "../../redux/notificationRedux";
import { getNotifications, updatedNotification } from "../../redux/apiCalls";
import { useEffect } from "react";
import {format} from 'timeago.js';


const NotificationList = () => {
    const dispatch = useDispatch();
    const notifications = useSelector(state => state.notification.notifications);
    const orderedNotifications = notifications.slice().sort((a, b) => b.createdAt.localeCompare(a.createdAt))

    useEffect(() => {
        getNotifications(dispatch)
    }, [dispatch]);

    const handleMarkAsRead = (notification) => {
        const notificationToUpdate = {
            ...notification,
            read: !notification.read
        }
        updatedNotification(notification._id, notificationToUpdate, dispatch);
    };

  return (
    <div className='notificationsContainer'>
        <h1 className="notificationsTitle">Notifications</h1>
        {notifications.map(notification => {
            return (
                <div className="notificationBlock" key={notification._id}>
                    <button className={notification.read ? "markRead" : "markNotRead"} onClick={() => handleMarkAsRead(notification)}></button>
                    <div className={notification.read ? "notificationDetails read" : "notificationDetails notRead"} onClick={() => handleMarkAsRead(notification)}>
                        <div className="topLine">
                           <b>Received from username</b>: {notification.username}
                        </div>
                        <div className="middleLine">
                            <div className="emailLine"><b>Email</b>: {notification.email}</div>
                        </div>
                        <div className="middleLine">
                            <div className="subjectLine"><b>Subject</b>: {notification.subject}</div>
                        </div>
                        <div className="messageBlock">
                            <div className="messageLine">{notification.message.substring(0,100)}...</div>
                        </div>
                        <div className="bottomLine">
                            ({format(notification.createdAt)})
                        </div>
                    </div>
                    <NavLink to={`/notification/${notification._id}`} className="viewLink">
                        View Notification
                    </NavLink>
                </div>
            )
        })}
    </div>
  )
}

export default NotificationList
